div.script:
document.addEventListener('DOMContentLoaded', function() {
    // Check if product was selected from catalog
    const selectedProductId = sessionStorage.getItem('selectedProductId');
    const selectedCategoryId = sessionStorage.getItem('selectedCategoryId');
    if (selectedProductId) {
        // Clear session storage
        sessionStorage.removeItem('selectedProductId');
        sessionStorage.removeItem('selectedCategoryId');

        // Wait for form to be ready, then add product
        setTimeout(function() {
            const tbody = document.getElementById('order_lines_tbody');
            if (tbody) {
                const rows = tbody.querySelectorAll('.order_line_row');
                let targetRow = null;

                // Find first empty row
                for (let row of rows) {
                    const productSelect = row.querySelector('.product_select');
                    if (!productSelect || !productSelect.value) {
                        targetRow = row;
                        break;
                    }
                }

                if (targetRow) {
                    // Set category if provided
                    if (selectedCategoryId) {
                        const categorySelect = targetRow.querySelector('.category_select');
                        if (categorySelect) {
                            categorySelect.value = selectedCategoryId;
                            categorySelect.dispatchEvent(new Event('change'));
                        }
                    }

                    // Wait a bit for category change to process, then set product
                    setTimeout(function() {
                        const productSelect = targetRow.querySelector('.product_select');
                        if (productSelect) {
                            productSelect.value = selectedProductId;
                            productSelect.dispatchEvent(new Event('change'));
                        }
                    }, 300);
                }
            }
        }, 500);
    }

    // Skip all JS if in readonly mode
    const isReadonly = window.purchaseOrderFormReadonly === 'true';
    if (isReadonly) {
        return; // Don't initialize any form functionality
    }

    // Get CSRF token from meta tag
    const csrfMeta = document.querySelector('meta[name="csrf-token"]');
    window.odoo = window.odoo || {};
    window.odoo.csrf_token = csrfMeta ? csrfMeta.content : '';

    // Load addresses, notes, and shipping option when customer changes
    const customerSelect = document.getElementById('customer');
    const invoiceAddressInput = document.getElementById('invoice_address');
    const deliveryAddressSelect = document.getElementById('delivery_address');
    const notesTextarea = document.getElementById('notes');
    const shippingOptionSelect = document.getElementById('shipping_option_dropship');

    if (!customerSelect || !invoiceAddressInput || !deliveryAddressSelect || !notesTextarea || !shippingOptionSelect) {
        console.error('Required form elements not found');
        return;
    }

    customerSelect.addEventListener('change', function() {
        const customerId = this.value;
        if (customerId) {
            fetch('/my/purchase_orders_form/get_addresses', {
                method: 'POST',
                credentials: 'same-origin',
                headers: {
                    'Content-Type': 'application/json',
                    'X-Requested-With': 'XMLHttpRequest',
                    'X-CSRF-TOKEN': window.odoo && window.odoo.csrf_token ? window.odoo.csrf_token : '',
                },
                body: JSON.stringify({
                    jsonrpc: '2.0',
                    method: 'call',
                    params: { customer_id: parseInt(customerId) }
                })
            })
            .then(response => {
                if (!response.ok) throw new Error(`HTTP error! Status: ${response.status}`);
                return response.json();
            })
            .then(data => {
                const result = data.result || data;
                const invoiceAddresses = result.invoice_addresses || [];
                const deliveryAddresses = result.delivery_addresses || [];
                const notes = result.notes || '';
                const shippingOption = result.shipping_option_dropship || '';

                // Auto-patch invoice address (from dealer) - show first one
                const invoiceAddressIdInput = document.getElementById('invoice_address_id');
                if (invoiceAddresses.length > 0) {
                    const firstInvoiceAddr = invoiceAddresses[0];
                    invoiceAddressInput.value = firstInvoiceAddr.label || firstInvoiceAddr.name || firstInvoiceAddr.display_name || '';
                    if (invoiceAddressIdInput) {
                        invoiceAddressIdInput.value = firstInvoiceAddr.id;
                    }
                } else {
                    invoiceAddressInput.value = '';
                    if (invoiceAddressIdInput) {
                        invoiceAddressIdInput.value = '';
                    }
                }

                // Populate delivery addresses dropdown
                deliveryAddressSelect.innerHTML = '<option value="">Select Delivery Address</option>';
                deliveryAddresses.forEach(addr => {
                    const option = document.createElement('option');
                    option.value = addr.id;
                    option.textContent = addr.label || addr.name || addr.display_name;
                    deliveryAddressSelect.appendChild(option);
                });

                // Auto-patch notes from customer
                notesTextarea.value = notes;

                // Auto-patch shipping option from customer
                shippingOptionSelect.value = shippingOption;
            })
            .catch(err => {
                console.error('Error loading addresses:', err);
                alert('Error loading addresses. Please check the console for details.');
            });
        } else {
            invoiceAddressInput.value = '';
            deliveryAddressSelect.innerHTML = '<option value="">Select Delivery Address</option>';
            notesTextarea.value = '';
            shippingOptionSelect.value = '';
        }
    });

    // Add line functionality
    const addLineBtn = document.getElementById('add_line_btn');
    const tbody = document.getElementById('order_lines_tbody');

    // Remove line functionality
    tbody.addEventListener('click', function(e) {
        const btn = e.target.closest('.remove_line_btn');
        if (!btn) return;

        const row = btn.closest('.order_line_row');
        if (tbody.querySelectorAll('.order_line_row').length > 1) {
            row.remove();
        } else {
            alert('At least one line is required');
        }
    });

    // Auto-select UOM, price, and display taxes when product is selected
    tbody.addEventListener('change', function(e) {
        if (!e.target.classList.contains('product_select')) return;

        const row = e.target.closest('.order_line_row');
        const productId = e.target.value;
        const selectedOption = e.target.options[e.target.selectedIndex];
        const uomId = selectedOption.getAttribute('data-uom');

        if (uomId) row.querySelector('.uom_select').value = uomId;

        // If no product selected, reset tax rate and clear tax display
        if (!productId) {
            row.setAttribute('data-tax-rate', '0');
            row.querySelector('.tax_display').innerHTML = '';
            row.querySelector('.tax_ids_hidden').value = '';
            calculateLineAmount(row);
            return;
        }

        if (productId) {
            fetch('/my/purchase_orders_form/get_product_info', {
                method: 'POST',
                credentials: 'same-origin',
                headers: {
                    'Content-Type': 'application/json',
                    'X-Requested-With': 'XMLHttpRequest',
                    'X-CSRF-TOKEN': window.odoo && window.odoo.csrf_token ? window.odoo.csrf_token : '',
                },
                body: JSON.stringify({
                    jsonrpc: '2.0',
                    method: 'call',
                    params: { product_id: parseInt(productId) }
                })
            })
            .then(response => response.json())
            .then(data => {
                const result = data.result || {};

                // Set price
                if (result.list_price) {
                    row.querySelector('.price_unit_input').value = result.list_price;
                }

                // Set UOM if not already set
                if (result.uom_id) row.querySelector('.uom_select').value = result.uom_id[0];

                // Display taxes as badges and store tax rates
                if (result.taxes) {
                    const taxDisplay = row.querySelector('.tax_display');
                    const taxHidden = row.querySelector('.tax_ids_hidden');

                    taxDisplay.innerHTML = '';
                    const taxIds = [];
                    let totalTaxRate = 0;

                    result.taxes.forEach(tax => {
                        taxIds.push(tax.id);
                        // tax.amount is already a percentage (e.g., 15 for 15%)
                        // tax.rate is the decimal version (e.g., 0.15 for 15%)
                        const taxRateDecimal = parseFloat(tax.rate) || (parseFloat(tax.amount) / 100) || 0;
                        totalTaxRate += taxRateDecimal;

                        const span = document.createElement('span');
                        span.className = 'badge bg-secondary me-1';
                        // Display tax as percentage (tax.amount is already in percentage form)
                        const taxPercent = parseFloat(tax.amount) || 0;
                        span.textContent = taxPercent.toFixed(0) + '%';
                        taxDisplay.appendChild(span);
                    });

                    taxHidden.value = taxIds.join(',');

                    // Store total tax rate (as decimal) in data attribute for calculation
                    row.setAttribute('data-tax-rate', totalTaxRate.toString());
                } else {
                    // No taxes, set tax rate to 0
                    row.setAttribute('data-tax-rate', '0');
                }

                // Calculate amount after price is set
                calculateLineAmount(row);
            })
            .catch(err => console.error('Error loading product info:', err));
        }
    });

    // function to calculate line amount (including taxes)
    function calculateLineAmount(row) {
        const quantityInput = row.querySelector('.quantity_input');
        const priceInput = row.querySelector('.price_unit_input');
        const amountDisplay = row.querySelector('.amount_display');
        const amountHidden = row.querySelector('.amount_hidden');

        if (quantityInput && priceInput && amountDisplay) {
            const quantity = parseFloat(quantityInput.value) || 0;
            const price = parseFloat(priceInput.value) || 0;

            // Get tax rate from data attribute (stored as decimal, e.g., 0.15 for 15%)
            const taxRate = parseFloat(row.getAttribute('data-tax-rate')) || 0;

            // Simple calculation: price * quantity * (1 + tax_rate)
            // Example: 100 * 1 * (1 + 0.15) = 115
            const amount = price * quantity * (1 + taxRate);

            amountDisplay.value = amount.toFixed(2);
            if (amountHidden) {
                amountHidden.value = amount.toFixed(2);
            }

            return amount;
        }
        return 0;
    }

    // function to recalculate all amounts
    function recalculateAllAmounts() {
        const rows = document.querySelectorAll('.order_line_row');
        let total = 0;

        rows.forEach(row => {
            total += calculateLineAmount(row);
        });

        return total;
    }

    // amount calculation when quantity or price changes
    tbody.addEventListener('input', function(e) {
        if (e.target.classList.contains('quantity_input') ||
            e.target.classList.contains('price_unit_input')) {
            const row = e.target.closest('.order_line_row');
            calculateLineAmount(row);
        }
    });

    // Category change handler - filter products
    tbody.addEventListener('change', function(e) {
        if (!e.target.classList.contains('category_select')) return;

        const row = e.target.closest('.order_line_row');
        const categoryId = e.target.value;
        const productSelect = row.querySelector('.product_select');
        const currentProductId = productSelect.value;

        // Clear product selection when category changes
        productSelect.innerHTML = '<option value="">Select Product</option>';

        // Fetch products by category
        fetch('/my/purchase_orders_form/get_products_by_category', {
            method: 'POST',
            credentials: 'same-origin',
            headers: {
                'Content-Type': 'application/json',
                'X-Requested-With': 'XMLHttpRequest',
                'X-CSRF-TOKEN': window.odoo && window.odoo.csrf_token ? window.odoo.csrf_token : '',
            },
            body: JSON.stringify({
                jsonrpc: '2.0',
                method: 'call',
                params: { category_id: categoryId ? parseInt(categoryId) : null }
            })
        })
        .then(response => response.json())
        .then(data => {
            const result = data.result || data;
            const products = result.products || [];

            products.forEach(product => {
                const option = document.createElement('option');
                option.value = product.id;
                option.textContent = product.display_name || product.name;
                option.setAttribute('data-uom', product.uom_id || '');
                productSelect.appendChild(option);
            });

            // Try to restore previous selection if it's still available
            if (currentProductId) {
                const option = productSelect.querySelector(`option[value="${currentProductId}"]`);
                if (option) {
                    productSelect.value = currentProductId;
                    // Trigger product change to load product info
                    productSelect.dispatchEvent(new Event('change'));
                }
            }
        })
        .catch(err => {
            console.error('Error loading products:', err);
        });
    });

    // Add line button event listener (single listener to prevent duplicate rows)
    addLineBtn.addEventListener('click', function() {
        const firstRow = tbody.querySelector('.order_line_row');
        if (!firstRow) return;

        const newRow = firstRow.cloneNode(true);

        // Clear values
        newRow.querySelector('.category_select').value = '';
        newRow.querySelector('.product_select').value = '';
        newRow.querySelector('.product_select').innerHTML = '<option value="">Select Product</option>';
        // Re-populate products dropdown (all products when no category)
        fetch('/my/purchase_orders_form/get_products_by_category', {
            method: 'POST',
            credentials: 'same-origin',
            headers: {
                'Content-Type': 'application/json',
                'X-Requested-With': 'XMLHttpRequest',
                'X-CSRF-TOKEN': window.odoo && window.odoo.csrf_token ? window.odoo.csrf_token : '',
            },
            body: JSON.stringify({
                jsonrpc: '2.0',
                method: 'call',
                params: { category_id: null }
            })
        })
        .then(response => response.json())
        .then(data => {
            const result = data.result || data;
            const products = result.products || [];
            const productSelect = newRow.querySelector('.product_select');
            products.forEach(product => {
                const option = document.createElement('option');
                option.value = product.id;
                option.textContent = product.display_name || product.name;
                option.setAttribute('data-uom', product.uom_id || '');
                productSelect.appendChild(option);
            });
        })
        .catch(err => console.error('Error loading products:', err));

        newRow.querySelector('.quantity_input').value = '1';
        newRow.querySelector('.uom_select').value = '';
        newRow.querySelector('.price_unit_input').value = '0';
        newRow.querySelector('.amount_display').value = '0.00';
        newRow.querySelector('.amount_hidden').value = '0.00';
        newRow.querySelector('.tax_display').innerHTML = '';
        newRow.querySelector('.tax_ids_hidden').value = '';
        newRow.setAttribute('data-tax-rate', '0'); // Reset tax rate

        tbody.appendChild(newRow);
    });

    // amount calculation when product is selected (price might be auto-filled)
    tbody.addEventListener('change', function(e) {
        if (e.target.classList.contains('product_select')) {
            // Wait a moment for price to be set
            setTimeout(() => {
                const row = e.target.closest('.order_line_row');
                calculateLineAmount(row);
            }, 200);
        }
    });

    // Form submission validation - filter out empty rows
    const form = document.getElementById('purchase_order_form');
    form.addEventListener('submit', function(e) {
        const rows = tbody.querySelectorAll('.order_line_row');
        let hasValidRow = false;

        rows.forEach(row => {
            const productSelect = row.querySelector('.product_select');
            const productId = productSelect ? productSelect.value : '';

            if (productId && productId.trim() !== '') {
                hasValidRow = true;
            } else {
                const inputs = row.querySelectorAll('input, select');
                inputs.forEach(input => input.disabled = true);
            }
        });

        if (!hasValidRow) {
            e.preventDefault();
            alert('At least one valid order line with a product is required.');
            return false;
        }
    });

    // Initialize amounts on page load
    const initialRows = tbody.querySelectorAll('.order_line_row');
    initialRows.forEach(row => {
        // Set initial tax rate to 0 if not set
        if (!row.getAttribute('data-tax-rate')) {
            row.setAttribute('data-tax-rate', '0');
        }
        calculateLineAmount(row);
    });

});
